import { useState, useEffect, useCallback, useMemo, useRef } from 'react'
import { AppState } from 'react-native'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { getTodayLocal, isProtocolActiveOnDate, getNow, parseISO, addDays } from '@dosiq/core'
import { supabase } from '../../../platform/supabase/nativeSupabaseClient'
import { getStockData } from '../services/stockService'

const STOCK_CACHE_KEY = '@dosiq/stock-snapshot'

/**
 * Hook para gerenciar e calcular dados de estoque conforme ADR-018.
 */
export function useStock() {
  const [state, setState] = useState({
    data: null,
    loading: true,
    error: null,
    stale: false,
    refreshing: false
  })

  // Ref para verificação de snapshot (R-184)
  const dataRef = useRef(null)

  const loadStock = useCallback(async (isRefreshing = false) => {
    if (isRefreshing) setState(prev => ({ ...prev, refreshing: true, error: null }))
    else setState(prev => ({ ...prev, loading: true, error: null }))

    try {
      const { data: { session: currentSession }, error: sessionError } = await supabase.auth.getSession()

      let user = currentSession?.user
      if (sessionError || !user) {
        const { data: { user: verifiedUser }, error: userError } = await supabase.auth.getUser()
        if (userError || !verifiedUser) throw new Error('Sessão expirada')
        user = verifiedUser
      }

      const result = await getStockData(user.id)
      const today = getTodayLocal()

      if (!result.success) throw new Error(result.error)

      // 1. Processamento base e cálculo ADR-018
      const processed = result.data.map(item => {
        const totalQuantity = item.medicine_stock_summary?.[0]?.total_quantity || 0

        // Filtro de validade temporal (Wave v0.1.5)
        const activeProtocols = (item.protocols || []).filter(p => 
          p.active && isProtocolActiveOnDate(p, today)
        )

        const dailyConsumption = activeProtocols.reduce((acc, p) => {
          const intakesPerDay = (p.time_schedule || []).length || 1
          return acc + (Number(p.dosage_per_intake) * intakesPerDay)
        }, 0)

        const daysRemaining = dailyConsumption > 0 
          ? totalQuantity / dailyConsumption 
          : Infinity

        let status = 'HIGH'
        let statusLabel = 'Bom'
        let color = '#3b82f6'

        if (daysRemaining < 7) {
          status = 'CRITICAL'
          statusLabel = 'Crítico'
          color = '#ef4444'
        } else if (daysRemaining < 14) {
          status = 'LOW'
          statusLabel = 'Baixo'
          color = '#f59e0b'
        } else if (daysRemaining < 30) {
          status = 'NORMAL'
          statusLabel = 'Normal'
          color = '#22c55e'
        } else {
          status = 'HIGH'
          statusLabel = 'Bom'
          color = '#3b82f6'
        }

        return {
          ...item,
          totalQuantity,
          dailyConsumption,
          daysRemaining,
          status,
          statusLabel,
          color,
          hasActiveProtocol: activeProtocols.length > 0,
          // Mantemos os protocolos para garantir que o snapshot contenha as datas para re-processamento se necessário
          activeProtocols 
        }
      })

      // Na fase Read-Only Mobile, filtramos RIGOROSAMENTE para mostrar apenas o que tem protocolo hoje
      const active = processed
        .filter(item => item.hasActiveProtocol)
        .sort((a, b) => a.daysRemaining - b.daysRemaining)

      // Nota: Não mostramos a lista de inativos no Read-Only mobile por enquanto (reduzir ruído)
      const newData = { 
        active, 
        inactive: [],
        localDay: today // R-114 fix: salvar dia local explícito
      }
      const snapshot = {
        data: newData,
        capturedAt: getNow().toISOString(),
        rawData: result.data // Salvamos o raw para resiliência de cache total se o dia mudar
      }

      await AsyncStorage.setItem(STOCK_CACHE_KEY, JSON.stringify(snapshot))

      dataRef.current = newData
      setState({
        data: newData,
        loading: false,
        error: null,
        stale: false,
        refreshing: false
      })
    } catch (err) {
      if (__DEV__) console.warn('[useStock] Fetch failed, checking cache:', err.message)

      try {
        const cached = await AsyncStorage.getItem(STOCK_CACHE_KEY)
        if (cached) {
          const parsed = JSON.parse(cached)
          const capturedAt = parseISO(parsed.capturedAt)
          const now = getNow()
          const diffHours = (now.getTime() - capturedAt.getTime()) / (1000 * 60 * 60)

          if (diffHours < 24) {
            dataRef.current = parsed.data
            setState({
              data: parsed.data,
              loading: false,
              error: null,
              stale: true,
              refreshing: false
            })
          } else {
            throw new Error('Cache expirado')
          }
        } else {
          throw err
        }
      } catch (cacheErr) {
        setState(prev => ({
          ...prev,
          loading: false,
          refreshing: false,
          error: err.message
        }))
      }
    }
  }, [])

  useEffect(() => {
    loadStock()
  }, [loadStock])

  // Lógica de Refresh de Meia-Noite e AppState (R-184)
  useEffect(() => {
    let midnightTimer

    const scheduleMidnightRefresh = () => {
      const now = getNow()
      const nextMidnight = addDays(now, 1)
      nextMidnight.setHours(0, 0, 0, 0)

      const msUntilMidnight = nextMidnight.getTime() - now.getTime()

      clearTimeout(midnightTimer)
      midnightTimer = setTimeout(() => {
        if (__DEV__) console.log('[useStock] Meia-noite detectada: Refreshing...')
        loadStock()
        scheduleMidnightRefresh()
      }, msUntilMidnight + 1000)
    }

    scheduleMidnightRefresh()

    const handleStateChange = (nextState) => {
      if (nextState === 'active') {
        const today = getTodayLocal()
        if (dataRef.current?.localDay && dataRef.current.localDay !== today) {
          if (__DEV__) console.log('[useStock] Dia alterado via background: Refreshing...')
          loadStock()
        }
      }
    }

    const subscription = AppState.addEventListener('change', handleStateChange)
    return () => {
      subscription.remove()
      clearTimeout(midnightTimer)
    }
  }, [loadStock])

  // Resilience layer (Rule R-175): Double-check validity on the active list
  // Isso protege contra o caso do cache ter sido gerado às 23:59 de ontem e carregado às 00:01 de hoje.
  const refinedData = useMemo(() => {
    if (!state.data?.active) return state.data
    const today = getTodayLocal()

    const refinedActive = state.data.active.filter(item => {
      // Se o item já foi processado e tem activeProtocols salvos:
      if (item.activeProtocols) {
        return item.activeProtocols.some(p => isProtocolActiveOnDate(p, today))
      }
      // Fallback para protocols originais
      return (item.protocols || []).some(p => p.active && isProtocolActiveOnDate(p, today))
    })

    return { 
      ...state.data, 
      active: refinedActive 
    }
  }, [state.data])

  const result = useMemo(() => ({
    ...state,
    data: refinedData,
    refresh: () => loadStock(true)
  }), [state, refinedData, loadStock])

  return result
}

// ADR-029: thin local service — chama Supabase directamente via nativeSupabaseClient
// R-125: validação Zod na camada de serviço (R-NNN sugerido em review PR #467)

import { z } from 'zod'
import { getTodayLocal, isProtocolActiveOnDate } from '@dosiq/core'
import { supabase as nativeSupabaseClient } from '../../../platform/supabase/nativeSupabaseClient'

/**
 * Busca a lista de medicamentos com seu estoque e protocolos ativos para cálculo de consumo.
 * 
 * @param {string} userId - UUID do usuário
 * @returns {Promise<{success: boolean, data?: Array, error?: string}>}
 */
export async function getStockData(userId) {
  try {
    // Validação de entrada conforme R-125
    z.string().uuid().parse(userId)

    if (__DEV__) console.log('[stockService] Buscando dados de estoque para:', userId)

    // Buscamos medicamentos com: 
    // 1. Quantidade total (da view medicine_stock_summary)
    // 2. Protocolos ativos (para calcular consumo diário)
    // Nota: O join com medicine_stock_summary usa a relação automática baseada em medicine_id
    const { data: rawData, error } = await nativeSupabaseClient
      .from('medicines')
      .select(`
        id,
        name,
        laboratory,
        dosage_unit,
        dosage_per_pill,
        medicine_stock_summary!left (
          total_quantity
        ),
        protocols (
          id,
          dosage_per_intake,
          time_schedule,
          frequency,
          active,
          start_date,
          end_date
        )
      `)
      .eq('user_id', userId)
      .eq('protocols.active', true)
      .order('name')

    if (error) {
      console.error('[stockService] Erro na query:', error)
      return { success: false, error: 'Erro ao carregar dados de estoque' }
    }

    // Filtro de validade de protocolos (Wave v0.1.5)
    // Na fase Read-Only, só mostramos estoque do que tem tratamento "rodando" hoje.
    const today = getTodayLocal()
    const validData = (rawData || []).filter(m => {
      // Verifica se existe pelo menos um protocolo vinculado que seja válido para hoje
      const hasValidProtocol = (m.protocols || []).some(p => isProtocolActiveOnDate(p, today))
      return hasValidProtocol
    })

    return { success: true, data: validData }
  } catch (err) {
    console.error('[stockService] Erro inesperado:', err)
    return { success: false, error: err.message }
  }
}

// useTreatments.js — hook para listagem de tratamentos
// Padrão: { data, loading, error, stale, refresh }

import { useState, useEffect, useCallback, useRef, useMemo } from 'react'
import { AppState } from 'react-native'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { getTodayLocal, isProtocolActiveOnDate, getNow, addDays, parseISO } from '@dosiq/core'
import { supabase } from '../../../platform/supabase/nativeSupabaseClient'
import { getActiveTreatments } from '../services/treatmentsService'

const TREATMENTS_CACHE_KEY = '@dosiq/treatments-snapshot'

/**
 * @typedef {{ id: string, name: string, frequency: string, time_schedule: string[], dosage_per_intake: number, titration_status: string, medicine: { name: string, type: string } }} Treatment
 * @returns {{ data: Treatment[]|null, loading: boolean, error: string|null, stale: boolean, refresh: Function }}
 */
export function useTreatments() {
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [stale, setStale] = useState(false)
  const dataRef = useRef(null)

  const load = useCallback(async () => {
    // ... codigo de load ...
    setLoading(true)
    setError(null)

    try {
      const { data: authData, error: authError } = await supabase.auth.getUser()
      const user = authData?.user
      if (authError || !user) throw new Error('Sessão expirada.')

      const result = await getActiveTreatments(user.id)

      if (!result.success) throw new Error(result.error)

      const newData = result.data
      const today = getTodayLocal()
      const snapshot = {
        data: newData,
        capturedAt: getNow().toISOString(),
        localDay: today // R-114 fix
      }

      await AsyncStorage.setItem(TREATMENTS_CACHE_KEY, JSON.stringify(snapshot))

      dataRef.current = { data: newData, localDay: today }
      setData(newData)
      setStale(false)
    } catch (err) {
      if (__DEV__) console.warn('[useTreatments] Fetch failed, checking cache:', err.message)

      try {
        const cached = await AsyncStorage.getItem(TREATMENTS_CACHE_KEY)
        if (cached) {
          const parsed = JSON.parse(cached)
          const capturedAt = parseISO(parsed.capturedAt)
          const now = getNow()
          const diffHours = (now - capturedAt) / (1000 * 60 * 60)

          if (diffHours < 24) {
            setData(parsed.data)
            dataRef.current = { data: parsed.data, localDay: parsed.localDay }
            setStale(true)
            setError(null)
          } else {
            throw new Error('Cache expirado')
          }
        } else {
          throw err
        }
      } catch (cacheErr) {
        setError(err.message ?? 'Erro ao carregar tratamentos.')
      }
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    load()
  }, [load])

  // Lógica de Refresh de Meia-Noite e AppState (R-184)
  useEffect(() => {
    let midnightTimer

    const scheduleMidnightRefresh = () => {
      const now = getNow()
      const nextMidnight = addDays(now, 1)
      nextMidnight.setHours(0, 0, 0, 0)

      const msUntilMidnight = nextMidnight.getTime() - now.getTime()

      clearTimeout(midnightTimer)
      midnightTimer = setTimeout(() => {
        if (__DEV__) console.log('[useTreatments] Meia-noite detectada: Refreshing...')
        load()
        scheduleMidnightRefresh()
      }, msUntilMidnight + 1000)
    }

    scheduleMidnightRefresh()

    const handleStateChange = (nextState) => {
      if (nextState === 'active') {
        const today = getTodayLocal()
        if (dataRef.current?.localDay && dataRef.current.localDay !== today) {
          if (__DEV__) console.log('[useTreatments] Dia alterado via background: Refreshing...')
          load()
        }
      }
    }

    const subscription = AppState.addEventListener('change', handleStateChange)
    return () => {
      subscription.remove()
      clearTimeout(midnightTimer)
    }
  }, [load])

  // Resilience layer (Rule R-175): Filtrar validade para HOJE local.
  // Garante que mesmo que o snapshot no cache tenha dados de ontem, a UI oculte os expirados.
  // Resilience layer + Grouping (Rule R-175): Organizar por Planos/Classes
  const groupedData = useMemo(() => {
    if (!data) return null
    const today = getTodayLocal()

    // 1. Filtrar ativos para hoje e ordenar por horário da primeira dose
    const validProtocols = data
      .filter(p => isProtocolActiveOnDate(p, today))
      .sort((a, b) => {
        const timeA = (a.time_schedule && a.time_schedule[0]) || '99:99'
        const timeB = (b.time_schedule && b.time_schedule[0]) || '99:99'
        return timeA.localeCompare(timeB)
      })

    // 2. Agrupar
    const groupsMap = {}

    validProtocols.forEach(p => {
      let groupId, groupName, groupEmoji, groupColor

      if (p.treatment_plan) {
        // Via Plano de Tratamento (Prioridade 1)
        groupId = p.treatment_plan.id
        groupName = p.treatment_plan.name
        groupEmoji = p.treatment_plan.emoji
        groupColor = p.treatment_plan.color
      } else if (p.medicine?.therapeutic_class) {
        // Via Classe Terapêutica (Prioridade 2 - Fallback)
        groupId = `class-${p.medicine.therapeutic_class}`
        groupName = p.medicine.therapeutic_class
        groupEmoji = '🧪'
        groupColor = '#94a3b8' 
      } else {
        // Outros (Prioridade 3)
        groupId = 'general'
        groupName = 'Outros Tratamentos'
        groupEmoji = '💊'
        groupColor = '#cbd5e1'
      }

      if (!groupsMap[groupId]) {
        groupsMap[groupId] = {
          id: groupId,
          title: groupName,
          emoji: groupEmoji,
          color: groupColor,
          protocols: []
        }
      }
      groupsMap[groupId].protocols.push(p)
    })

    // Converter para array e ordenar grupos (Planos primeiro, depois alfabético)
    return Object.values(groupsMap).sort((a, b) => {
      if (a.id === 'general') return 1
      if (b.id === 'general') return -1
      return a.title.localeCompare(b.title)
    })
  }, [data]) // today é derivado de getTodayLocal() que é determinístico por dia

  const result = useMemo(() => ({ 
    data: groupedData, 
    loading, 
    error, 
    stale, 
    refresh: load 
  }), [groupedData, loading, error, stale, load])

  return result
}

