import { useEffect } from 'react'
import { AppState } from 'react-native'
import { SafeAreaProvider } from 'react-native-safe-area-context'
import { requestTrackingPermissionsAsync, getTrackingPermissionsAsync } from 'expo-tracking-transparency'
import Navigation from './Navigation'

// AppRoot — ponto de entrada da árvore de componentes
export default function AppRoot() {
  useEffect(() => {
    let isRequesting = false

    const requestTracking = async () => {
      // Evita chamadas duplicadas simultâneas
      if (isRequesting) return
      isRequesting = true

      try {
        // Verifica o status atual antes de pedir
        const { status: currentStatus } = await getTrackingPermissionsAsync()

        // Só pede se ainda não foi determinado (primeira vez)
        if (currentStatus === 'undetermined') {
          // Pequeno delay para garantir que a UI do sistema está pronta
          await new Promise(resolve => setTimeout(resolve, 1000))

          const { status } = await requestTrackingPermissionsAsync()
          if (__DEV__) {
            console.log(`[Tracking] Resultado da solicitação: ${status}`)
          }
        }
      } catch (error) {
        if (__DEV__) console.warn('[Tracking] Falha ao solicitar permissão:', error)
      } finally {
        isRequesting = false
      }
    }

    // Tenta solicitar no mount inicial
    if (AppState.currentState === 'active') {
      requestTracking()
    }

    // Listener para garantir que se o app entrou em background e voltou, ou se o mount foi rápido demais
    const subscription = AppState.addEventListener('change', (nextAppState) => {
      if (nextAppState === 'active') {
        requestTracking()
      }
    })

    return () => subscription.remove()
  }, [])

  return (
    <SafeAreaProvider>
      <Navigation />
    </SafeAreaProvider>
  )
}

// Navigation.jsx — navegação auth-aware do app mobile
// R-164 (AP-H10): 3 estados obrigatórios (undefined/null/session)
//   undefined = a verificar sessão → spinner
//   null      = sem sessão         → LOGIN
//   object    = sessão activa      → TABS (shell do produto)
//
// CRÍTICO: NÃO simplificar — SecureStore chunked é assíncrono;
//   se montarmos o Navigator antes de getSession() resolver,
//   o utilizador sempre vê LOGIN mesmo com sessão válida guardada.

import { useEffect, useState } from 'react'
import { View, ActivityIndicator } from 'react-native'
import { NavigationContainer, createNavigationContainerRef } from '@react-navigation/native'
import { createNativeStackNavigator } from '@react-navigation/native-stack'
import { ROUTES } from './routes'
import SmokeScreen from '../screens/SmokeScreen'
import LoginScreen from '../screens/LoginScreen'
import RootTabs from './RootTabs'
import { supabase } from '../platform/supabase/nativeSupabaseClient'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { usePushNotifications } from '../platform/notifications/usePushNotifications'
import { logScreenView } from '../platform/analytics/firebaseAnalytics'

const Stack = createNativeStackNavigator()

// Ref de nível de módulo — permite importação externa para deeplink (R-164, N1.4)
// createNavigationContainerRef enfileira ações automaticamente se o navigator não estiver pronto
export const navigationRef = createNavigationContainerRef()

export default function Navigation() {
  // undefined = a verificar; null = sem sessão; object = sessão activa
  const [session, setSession] = useState(undefined)

  // Setup push notifications pós-login (H6.3)
  usePushNotifications({ supabase, session })

  // Handler para rastrear mudanças de tela — getCurrentRoute é mais robusto com nested navigators
  const handleNavigationStateChange = () => {
    const routeName = navigationRef.current?.getCurrentRoute?.()?.name
    if (routeName) {
      logScreenView(routeName)
    }
  }

  useEffect(() => {
    // Restaurar sessão persistida (SecureStore chunked — R-160)
    supabase.auth.getSession()
      .then(({ data: { session: s } }) => {
        setSession(s ?? null)
      })
      .catch((error) => {
        console.error('Erro ao restaurar sessão:', error)
        setSession(null) // null = sem sessão → redirige para LOGIN
      })

    // Actualizar em tempo real quando auth muda (login/logout)
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, s) => {
      if (event === 'SIGNED_OUT') {
        if (__DEV__) console.log('[Navigation] User signed out, clearing caches...')
        await AsyncStorage.multiRemove([
          '@dosiq/today-snapshot',
          '@dosiq/treatments-snapshot',
          '@dosiq/stock-snapshot'
        ])
      }
      setSession(s ?? null)
    })

    return () => subscription.unsubscribe()
  }, [])


  // Aguarda verificação inicial — evita flash de ecrã errado
  if (session === undefined) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <ActivityIndicator size="large" color="#2563eb" />
      </View>
    )
  }

  return (
    <NavigationContainer
      ref={navigationRef}
      onStateChange={handleNavigationStateChange}
    >
      <Stack.Navigator
        screenOptions={{ headerShown: false }}
      >
        {/* Renderização condicional baseada no estado da sessão */}
        {session ? (
          // Utilizador autenticado → renderizar shell do produto (tabs)
          <Stack.Screen name={ROUTES.TABS} component={RootTabs} />
        ) : (
          // Sem sessão → renderizar login e smoke (diag)
          <>
            <Stack.Screen name={ROUTES.LOGIN} component={LoginScreen} />
            <Stack.Screen
              name={ROUTES.SMOKE}
              component={SmokeScreen}
              options={{ headerShown: true, title: 'Smoke Test' }}
            />
          </>
        )}
      </Stack.Navigator>
    </NavigationContainer>
  )
}

// authService.js — serviço de autenticação com validação Zod
import { z } from 'zod'
import { supabase } from '@platform/supabase/nativeSupabaseClient'

/**
 * Schema para validação de credenciais de login
 */
const loginCredentialsSchema = z.object({
  email: z.string().email('Email inválido').trim(),
  password: z.string().min(1, 'Senha é obrigatória'),
})

/**
 * Traduz erros do Supabase Auth para mensagens amigáveis em português
 * @param {Error} authError - Erro retornado pelo Supabase Auth
 * @returns {string} Mensagem de erro traduzida
 */
function translateAuthError(authError) {
  if (!authError) return null

  const message = authError.message?.toLowerCase() || ''

  if (message.includes('invalid login credentials')) {
    return 'Email ou senha inválidos'
  }
  if (message.includes('user not found')) {
    return 'Usuário não encontrado'
  }
  if (message.includes('email not confirmed')) {
    return 'Email não confirmado'
  }
  if (message.includes('password too long')) {
    return 'Senha muito longa'
  }
  if (message.includes('email_not_authenticated')) {
    return 'Email não autenticado'
  }
  if (message.includes('rate limit')) {
    return 'Muitas tentativas de login. Tente novamente mais tarde'
  }

  // Fallback: retorna mensagem original se não conseguir traduzir
  return authError.message || 'Erro ao fazer login'
}

/**
 * Realiza login com email e senha
 * @param {string} email - Email do usuário
 * @param {string} password - Senha do usuário
 * @returns {Promise<{success: boolean, error?: string}>}
 */
export async function signInWithEmail(email, password) {
  // Validação com Zod
  const validation = loginCredentialsSchema.safeParse({ email, password })

  if (!validation.success) {
    const errorMessage = validation.error.issues[0]?.message || 'Dados inválidos'
    return { success: false, error: errorMessage }
  }

  try {
    const { error: authError } = await supabase.auth.signInWithPassword({
      email: validation.data.email,
      password: validation.data.password,
    })

    if (authError) {
      const translatedError = translateAuthError(authError)
      return { success: false, error: translatedError }
    }

    return { success: true }
  } catch (err) {
    return { success: false, error: 'Erro inesperado ao fazer login' }
  }
}

/**
 * Faz logout do usuário
 * @returns {Promise<{success: boolean}>}
 */
export async function signOut() {
  try {
    const { error } = await supabase.auth.signOut()
    if (error) {
      console.error('Erro ao fazer logout:', error.message)
      return { success: false }
    }
    return { success: true }
  } catch (err) {
    console.error('Erro inesperado ao fazer logout:', err)
    return { success: false }
  }
}

export default { signInWithEmail, signOut }

// Hook para setup de push notifications pós-login
// Configura: permissão, token registration, notification handlers
// Cleanup automático em logout (via dependencies)
// N1.4: deeplink real via navigationRef (foreground/background tap + cold start)

import { useEffect, useRef } from 'react'
import * as Notifications from 'expo-notifications'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { requestPushPermission } from './requestPushPermission'
import { getExpoPushToken } from './getExpoPushToken'
import { syncNotificationDevice } from './syncNotificationDevice'
import { unregisterNotificationDevice } from './unregisterNotificationDevice'
import { navigationRef } from '../../navigation/Navigation'
import { ROUTES } from '../../navigation/routes'

const PUSH_TOKEN_KEY = '@dosiq/expo-push-token'

// Mapa de screen names do payload para rotas do navigator
const SCREEN_TO_ROUTE = {
  'bulk-plan': ROUTES.TODAY,
  'bulk-misc': ROUTES.TODAY,
  'dose-individual': ROUTES.TODAY,
}

// Navega para a tela correta a partir de um tap em push notification.
// createNavigationContainerRef enfileira ações automaticamente — sem listener fallback necessário.
function navigateFromPush(navigationData) {
  const screen = navigationData?.screen
  const params = navigationData?.params ?? {}
  const targetRoute = (screen && SCREEN_TO_ROUTE[screen]) ?? ROUTES.TODAY

  // Incluir screen nos params para que TodayScreen identifique qual modal abrir
  navigationRef.navigate(targetRoute, screen ? { screen, ...params } : params)

  if (__DEV__) {
    console.log('[usePushNotifications] Navegando para:', targetRoute, 'params:', params)
  }
}

export function usePushNotifications({ supabase, session }) {
  // Flag para garantir que o cold start seja processado apenas uma vez por ciclo de vida do app,
  // mesmo que o useEffect re-execute em logout+login sem fechar o app.
  const coldStartProcessed = useRef(false)

  useEffect(() => {
    if (!session || !supabase) return

    let isMounted = true
    let notificationSubscription

    async function setupPush() {
      try {
        // Cold start: processar resposta pendente apenas uma vez por ciclo de vida do app
        if (!coldStartProcessed.current) {
          coldStartProcessed.current = true
          const lastResponse = await Notifications.getLastNotificationResponseAsync()
          if (lastResponse && isMounted) {
            const navigationData = lastResponse.notification.request.content.data?.navigation
            navigateFromPush(navigationData)
          }
        }

        const { granted } = await requestPushPermission()

        if (!granted) {
          if (__DEV__) console.log('[usePushNotifications] Permissão de push não concedida')
          return
        }

        const token = await getExpoPushToken()
        if (!isMounted) return

        await syncNotificationDevice({
          supabase,
          userId: session.user.id,
          token,
        })

        await AsyncStorage.setItem(PUSH_TOKEN_KEY, token)

        // Configurar handlers (conforme spec Passo 5)
        Notifications.setNotificationHandler({
          handleNotification: async () => ({
            shouldShowBanner: true,
            shouldShowList: true,
            shouldPlaySound: true,
            shouldSetBadge: false,
          }),
        })

        // Handler de tap em notificação (foreground / background)
        notificationSubscription = Notifications.addNotificationResponseReceivedListener(
          (response) => {
            const navigationData = response.notification.request.content.data?.navigation
            navigateFromPush(navigationData)
          }
        )

        if (__DEV__) {
          console.log('[usePushNotifications] Push setup completo: token =', token.substring(0, 20) + '...')
        }
      } catch (error) {
        if (isMounted && __DEV__) {
          console.error('[usePushNotifications] Erro durante setup:', error.message)
        }
      }
    }

    setupPush()

    return () => {
      isMounted = false
      notificationSubscription?.remove()
    }
  }, [supabase, session])

  // Cleanup durante logout: executa imediatamente quando session torna-se null,
  // não como cleanup da próxima renderização (que só correria no unmount)
  useEffect(() => {
    if (session) return
    ;(async () => {
      const token = await AsyncStorage.getItem(PUSH_TOKEN_KEY)
      if (token && supabase) {
        await unregisterNotificationDevice({ supabase, userId: null, token })
        await AsyncStorage.removeItem(PUSH_TOKEN_KEY)
      }
    })()
  }, [session, supabase])
}

// nativeSupabaseClient.js — cliente Supabase para o app native
// R4-004: o singleton pode existir no app mobile, mas NUNCA em packages/*
// AppState listener garante refresh de token quando app volta ao foreground

import { AppState } from 'react-native'
import { createClient } from '@supabase/supabase-js'
import { nativePublicAppConfig } from '../config/nativePublicAppConfig'
import { secureStoreAuthStorage } from '../auth/secureStoreAuthStorage'

function createNativeSupabaseClient() {
  // Debug: confirmar URL e que URLSearchParams está patchado antes do createClient
  if (__DEV__) console.log('[supabase-init] URL:', nativePublicAppConfig.supabaseUrl)
  if (__DEV__) console.log('[supabase-init] URLSearchParams.set type:', typeof global.URLSearchParams?.prototype?.set)
  const supabase = createClient(
    nativePublicAppConfig.supabaseUrl,
    nativePublicAppConfig.supabaseAnonKey,
    {
      auth: {
        // Sessão persiste entre aberturas do app via SecureStore
        storage: secureStoreAuthStorage,
        persistSession: true,
        autoRefreshToken: true,
        // Universal Links desabilitados no native nesta fase (DL-005)
        detectSessionInUrl: false,
      },
    }
  )

  // Pausa/retoma refresh automático com ciclo de vida do app
  AppState.addEventListener('change', (state) => {
    if (state === 'active') {
      supabase.auth.startAutoRefresh()
    } else {
      supabase.auth.stopAutoRefresh()
    }
  })

  return supabase
}

