/**
 * Prepara dados de adesão para o gráfico.
 * @param {Array} dailyAdherence - Dados diários de adesão.
 * @returns {Object} Dados formatados para renderAdherenceChart.
 * @private
 */
function prepareAdherenceChartData(dailyAdherence) {
  if (!dailyAdherence || dailyAdherence.length === 0) {
    return null
  }

  return {
    labels: dailyAdherence.map((day) => {
      // Formata data para DD/MM
      const date = parseLocalDate(day.date)
      return date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })
    }),
    values: dailyAdherence.map((day) => day.adherence || 0),
    expected: dailyAdherence.map((day) => day.expected || 0),
    taken: dailyAdherence.map((day) => day.taken || 0),
  }
}

/**
 * Prepara dados de estoque para o gráfico.
 * @param {Array} protocols - Lista de protocolos.
 * @param {Array} stockSummaries - Resumos de estoque.
 * @returns {Array} Dados formatados para renderStockChart.
 * @private
 */
function prepareStockChartData(protocols, stockSummaries) {
  if (!protocols || protocols.length === 0) {
    return []
  }

  return protocols
    .filter((protocol) => protocol.active && protocol.medicine)
    .map((protocol) => {
      const stock = stockSummaries.find((s) => s.medicine_id === protocol.medicine_id)
      return {
        name: protocol.medicine?.name || protocol.name,
        daysRemaining: stock ? calculateDaysRemaining(stock, protocol) : 0,
      }
    })
    .filter((item) => item.daysRemaining > 0)
    .sort((a, b) => a.daysRemaining - b.daysRemaining)
    .slice(0, 10) // Limita a 10 medicamentos
}

/**
 * Gera um relatório PDF completo.
 *
 * @param {Object} options - Opções de geração do relatório.
 * @param {string} [options.title='Dosiq - Relatório'] - Título do relatório.
 * @param {string} [options.period='30d'] - Período do relatório ('7d', '30d', '90d').
 * @param {boolean} [options.includeCharts=true] - Se deve incluir gráficos.
 * @param {boolean} [options.includeProtocols=true] - Se deve incluir tabela de protocolos.
 * @param {boolean} [options.includeStock=true] - Se deve incluir resumo de estoque.
 * @param {boolean} [options.includeRiskTable=true] - Se deve incluir tabela de risco por protocolo.
 * @returns {Promise<Blob>} Blob do PDF gerado.
 *
 * @example
 * // Geração básica
 * const pdfBlob = await generatePDF()
 *
 * // Com opções personalizadas
 * const pdfBlob = await generatePDF({
 *   title: 'Relatório Mensal',
 *   period: '30d',
 *   includeCharts: true
 * })
 *
 * // Download do PDF
 * const url = URL.createObjectURL(pdfBlob)
 * const a = document.createElement('a')
 * a.href = url
 * a.download = 'relatorio-medicamentos.pdf'
 * a.click()
 * URL.revokeObjectURL(url)
 */
export async function generatePDF(options = {}) {
  const startTime = getNow().getTime()
  const {
    title = 'Dosiq - Relatório',
    period = '30d',
    includeCharts = true,
    includeProtocols = true,
    includeStock = true,
    includeRiskTable = true,
  } = options

  logPDF('info', 'Iniciando geração do PDF', { title, period, options })

  try {
    // Lazy load TODOS os módulos pesados (jsPDF, services, chartRenderer)
    // Isso evita que o main bundle inclua vendor-pdf (589KB), feature-stock (139KB), etc.
    const [
      { jsPDF },
      { default: autoTable },
      { renderAdherenceChart, renderStockChart },
      { adherenceService },
      { protocolService },
      stockModule,
      riskModule,
      logModule,
    ] = await Promise.all([
      import('jspdf'),
      import('jspdf-autotable'),
      import('./chartRenderer.js'),
      import('@services/api/adherenceService.js'),
      import('@features/protocols/services/protocolService.js'),
      includeStock ? import('@features/stock/services/stockService.js') : Promise.resolve(null),
      includeRiskTable
        ? import('@adherence/services/protocolRiskService.js')
        : Promise.resolve(null),
      includeRiskTable ? import('@shared/services/api/logService.js') : Promise.resolve(null),
    ])

    const stockService = stockModule?.stockService
    const calculateAllProtocolRisks = riskModule?.calculateAllProtocolRisks
    const logService = logModule?.logService

    logPDF('info', 'Módulos carregados sob demanda', { library: 'jspdf + services + charts' })

    // Busca dados em paralelo
    const dataFetchStart = getNow().getTime()
    const today = getNow()
    const thirtyDaysAgo = addDays(today, -30)
    const startDateStr = formatLocalDate(thirtyDaysAgo)
    const endDateStr = formatLocalDate(today)

    const [adherenceSummary, dailyAdherence, protocols, lowStock, recentLogs] = await Promise.all([
      adherenceService.getAdherenceSummary(period),
      adherenceService.getDailyAdherence(30),
      includeProtocols ? protocolService.getAll() : Promise.resolve([]),
      includeStock && stockService ? stockService.getLowStockMedicines(100) : Promise.resolve([]),
      includeRiskTable && logService
        ? logService.getByDateRange(startDateStr, endDateStr, 500).then((r) => r.data ?? [])
        : Promise.resolve([]),
    ])

    logPDF('info', 'Dados buscados', {
      duration: `${getNow().getTime() - dataFetchStart}ms`,
      adherenceScore: adherenceSummary.overallScore,
      protocolsCount: protocols.length,
      lowStockCount: lowStock.length,
    })

    // Busca resumos de estoque para cada medicamento
    let stockSummaries = []
    if (includeStock && stockService && protocols.length > 0) {
      const medicineIds = [...new Set(protocols.map((p) => p.medicine_id).filter(Boolean))]
      stockSummaries = await Promise.all(medicineIds.map((id) => stockService.getStockSummary(id)))
    }

    // Cria documento PDF
    const doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4',
    })

    // Desenha cabeçalho
    drawHeader(doc, title, getNow())

    // Desenha resumo de adesão
    drawAdherenceSummary(doc, adherenceSummary)

    // Prepara e desenha gráfico de adesão
    let currentY = Y_POSITIONS.chartStart
    if (includeCharts) {
      const chartData = prepareAdherenceChartData(dailyAdherence)
      const chartImage = chartData ? renderAdherenceChart(chartData, 500, 200) : null
      currentY = drawAdherenceChart(doc, chartImage, currentY)
    }

    // Desenha tabela de protocolos
    if (includeProtocols) {
      currentY = drawProtocolsTable(doc, protocols, autoTable, currentY)
    }

    // Desenha tabela de risco por protocolo
    if (includeRiskTable && calculateAllProtocolRisks && protocols.length > 0) {
      const risks = calculateAllProtocolRisks({ protocols, logs: recentLogs })
      currentY = drawRiskTable(doc, risks, protocols, autoTable, currentY)
      logPDF('info', 'Tabela de risco adicionada', {
        protocolsWithData: risks.filter((r) => r.hasEnoughData).length,
        totalProtocols: risks.length,
      })
    }

    // Desenha resumo de estoque
    if (includeStock) {
      const stockChartData = prepareStockChartData(protocols, stockSummaries)
      const stockChartImage =
        stockChartData.length > 0 ? renderStockChart(stockChartData, 500, 150) : null
      drawStockSummary(doc, stockChartData, stockChartImage, currentY)
    }

    // Desenha rodapé
    drawFooter(doc)

    // Gera Blob
    const pdfBlob = doc.output('blob')

    const totalDuration = getNow().getTime() - startTime
    logPDF('info', 'PDF gerado com sucesso', {
      duration: `${totalDuration}ms`,
      blobSize: `${(pdfBlob.size / 1024).toFixed(2)}KB`,
      blobSizeMB: `${(pdfBlob.size / 1024 / 1024).toFixed(2)}MB`,
    })

    // Verifica tamanho do arquivo (<2MB)
    if (pdfBlob.size > 2 * 1024 * 1024) {
      logPDF('warn', 'PDF excede 2MB', {
        size: `${(pdfBlob.size / 1024 / 1024).toFixed(2)}MB`,
      })
    }

    return pdfBlob
  } catch (error) {
    logPDF('error', 'Erro ao gerar PDF', {
      error: error.message,
      stack: error.stack,
    })
    throw new Error(`Falha ao gerar relatório PDF: ${error.message}`)
  }
}

/**
 * Exporta todas as funções do módulo.
 */
export default {
  generatePDF,
}

/**
 * Service para compartilhamento de relatórios
 *
 * Fornece funções para upload de PDFs para compartilhamento temporário
 * e integração com Web Share API e Clipboard API.
 *
 * @module src/features/reports/services/shareService
 * @version 1.0.0
 */

import { supabase } from '@shared/utils/supabase'
import { getNow } from '@utils/dateUtils'

// ============================================================================
// CONFIGURAÇÃO
// ============================================================================

const API_ENDPOINT = '/api/share'

/**
 * Níveis de log disponíveis
 * @readonly
 */
const LOG_LEVELS = {
  DEBUG: 'debug',
  INFO: 'info',
  WARN: 'warn',
  ERROR: 'error',
}

// ============================================================================
// LOGGER ESTRUTURADO (R-087)
// ============================================================================

/**
 * Log estruturado com timestamp e contexto
 * @param {string} level - Nível do log (debug, info, warn, error)
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais para o log
 */
function log(level, message, data = {}) {
  const timestamp = getNow().toISOString()
  const logEntry = {
    timestamp,
    service: 'shareService',
    level,
    message,
    ...data,
  }

  const formattedMessage = `[shareService] ${message}`

  if (level === LOG_LEVELS.ERROR) {
    console.error(formattedMessage, logEntry)
  } else if (level === LOG_LEVELS.WARN) {
    console.warn(formattedMessage, logEntry)
  } else {
    console.log(formattedMessage, logEntry)
  }
}

/**
 * Log de informação
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logInfo(message, data = {}) {
  log(LOG_LEVELS.INFO, message, data)
}

/**
 * Log de erro
 * @param {string} message - Mensagem descritiva
 * @param {Error|Object} error - Erro ocorrido
 * @param {Object} additionalData - Dados adicionais de contexto
 */
function logError(message, error, additionalData = {}) {
  const errorDetails =
    error instanceof Error
      ? { name: error.name, message: error.message, stack: error.stack }
      : { error: String(error) }

  log(LOG_LEVELS.ERROR, message, { ...errorDetails, ...additionalData })
}

/**
 * Log de warning
 * @param {string} message - Mensagem descritiva
 * @param {Object} data - Dados adicionais
 */
function logWarn(message, data = {}) {
  log(LOG_LEVELS.WARN, message, data)
}

// ============================================================================
// FUNÇÕES PÚBLICAS
// ============================================================================

/**
 * Obtém o token de acesso JWT do Supabase
 * @returns {Promise<string|null>} Token JWT ou null se não autenticado
 */
async function getAuthToken() {
  try {
    const {
      data: { session },
    } = await supabase.auth.getSession()
    return session?.access_token || null
  } catch (error) {
    logError('Erro ao obter token de autenticação', error)
    return null
  }
}

/**
 * Faz upload de um relatório PDF para compartilhamento temporário
 *
 * @param {Blob} blob - Arquivo PDF em formato Blob
 * @param {Object} options - Opções de compartilhamento
 * @param {string} options.filename - Nome do arquivo (deve terminar com .pdf)
 * @param {number} [options.expiresInHours=72] - Tempo de expiração em horas (1-168)
 * @returns {Promise<Object>} Resultado com { url, expiresAt }
 * @throws {Error} Se o upload falhar ou usuário não estiver autenticado
 *
 * @example
 * const pdfBlob = await generatePDF()
 * const { url, expiresAt } = await shareReport(pdfBlob, {
 *   filename: 'relatorio-medicamentos.pdf',
 *   expiresInHours: 48
 * })
 */
export async function shareReport(blob, options) {
  const { filename, expiresInHours = 72 } = options

  logInfo('Iniciando compartilhamento de relatório', { filename, size: blob.size, expiresInHours })

  // Validar parâmetros
  if (!blob || !(blob instanceof Blob)) {
    throw new Error('Arquivo inválido. Envie um Blob válido.')
  }

  if (!filename || !filename.endsWith('.pdf')) {
    throw new Error('Nome do arquivo deve terminar com .pdf')
  }

  if (expiresInHours < 1 || expiresInHours > 168) {
    throw new Error('Tempo de expiração deve estar entre 1 e 168 horas')
  }

  // Verificar tamanho máximo (5MB)
  const maxSize = 5 * 1024 * 1024
  if (blob.size > maxSize) {
    throw new Error('Arquivo muito grande. Máximo de 5MB.')
  }

  // Obter token de autenticação
  const token = await getAuthToken()
  if (!token) {
    throw new Error('Usuário não autenticado. Faça login para compartilhar.')
  }

  // Converter Blob para base64
  let base64Data
  try {
    base64Data = await blobToBase64(blob)
    logInfo('Blob convertido para base64', { size: base64Data.length })
  } catch (error) {
    logError('Erro ao converter blob para base64', error)
    throw new Error('Erro ao processar arquivo')
  }

  // Fazer requisição para API
  try {
    const response = await fetch(API_ENDPOINT, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        blob: base64Data,
        filename,
        expiresInHours,
      }),
    })

    const result = await response.json()

    if (!response.ok || !result.success) {
      const errorMessage = result.error || 'Erro ao compartilhar relatório'
      logWarn('Falha no compartilhamento', { status: response.status, error: errorMessage })
      throw new Error(errorMessage)
    }

    logInfo('Relatório compartilhado com sucesso', { url: result.data?.url?.split('?')[0] })

    return {
      url: result.data.url,
      expiresAt: result.data.expiresAt,
    }
  } catch (error) {
    if (error.message === 'Failed to fetch') {
      logError('Erro de conexão com servidor', error)
      throw new Error('Erro de conexão. Verifique sua internet.')
    }
    throw error
  }
}

/**
 * Compartilha uma URL usando Web Share API nativa
 * Fallback para clipboard se não suportado
 *
 * @param {string} url - URL a ser compartilhada
 * @param {string} [title='Relatório'] - Título do compartilhamento
 * @returns {Promise<boolean>} true se compartilhado com sucesso
 *
 * @example
 * const success = await shareNative(url, 'Meu Relatório de Medicamentos')
 * if (!success) {
 *   // Usuário cancelou ou não suportado
 * }
 */
export async function shareNative(url, title = 'Relatório') {
  logInfo('Tentando compartilhamento nativo', { url: url.split('?')[0], title })

  if (!url) {
    throw new Error('URL é obrigatória')
  }

  // Verificar se Web Share API é suportada
  if (navigator.share) {
    try {
      await navigator.share({
        title,
        text: `Confira meu ${title.toLowerCase()}`,
        url,
      })
      logInfo('Compartilhamento nativo bem-sucedido')
      return true
    } catch (error) {
      // Usuário cancelou ou erro
      if (error.name === 'AbortError') {
        logInfo('Usuário cancelou compartilhamento')
        return false
      }
      logWarn('Erro no compartilhamento nativo', { error: error.message })
      // Continuar para fallback
    }
  }

  // Fallback para clipboard
  logInfo('Usando fallback para clipboard')
  try {
    await copyToClipboard(url)
    return true
  } catch (error) {
    logError('Fallback de clipboard falhou', error)
    throw new Error('Não foi possível compartilhar. Copie a URL manualmente.')
  }
}

/**
 * Copia uma URL para o clipboard
 * Usa Clipboard API moderna com fallback para método legacy
 *
 * @param {string} url - URL a ser copiada
 * @returns {Promise<void>}
 * @throws {Error} Se não conseguir copiar
 *
 * @example
 * await copyToClipboard('https://example.com/relatorio.pdf')
 * // Mostrar toast: "Link copiado para a área de transferência!"
 */
export async function copyToClipboard(url) {
  logInfo('Copiando para clipboard', { url: url.split('?')[0] })

  if (!url) {
    throw new Error('URL é obrigatória')
  }

  // Tentar Clipboard API moderna
  if (navigator.clipboard && window.isSecureContext) {
    try {
      await navigator.clipboard.writeText(url)
      logInfo('URL copiada com Clipboard API')
      return
    } catch (error) {
      logWarn('Clipboard API falhou, tentando fallback', { error: error.message })
    }
  }

  // Fallback para método legacy
  const textArea = document.createElement('textarea')
  textArea.value = url
  textArea.style.position = 'fixed'
  textArea.style.left = '-999999px'
  textArea.style.top = '-999999px'
  document.body.appendChild(textArea)

  try {
    textArea.focus()
    textArea.select()

    const successful = document.execCommand('copy')
    document.body.removeChild(textArea)

    if (successful) {
      logInfo('URL copiada com método legacy')
    } else {
      throw new Error('execCommand retornou false')
    }
  } catch (error) {
    document.body.removeChild(textArea)
    logError('Fallback de clipboard falhou', error)
    throw new Error('Não foi possível copiar o link. Copie manualmente.')
  }
}

// ============================================================================
// FUNÇÕES UTILITÁRIAS
// ============================================================================

/**
 * Converte Blob para string base64
 * @param {Blob} blob - Blob a ser convertido
 * @returns {Promise<string>} String em base64
 */
function blobToBase64(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onloadend = () => {
      const base64 = reader.result
      // Remover prefixo data:application/pdf;base64, se existir
      const cleanBase64 = base64.replace(/^data:.*?;base64,/, '')
      resolve(cleanBase64)
    }
    reader.onerror = reject
    reader.readAsDataURL(blob)
  })
}

